sed -i 's/const { username, email, password, role } = await c.req.json();/const body = await c.req.json();\n  const { username, email, password, role, displayName, status } = body;/' functions/api/[[path]].ts
sed -i 's/await c.env.DB.prepare('\''INSERT INTO users (id, username, email, password_hash, role) VALUES (?, ?, ?, ?, ?)'\'')/await ensureTableAndColumns(c.env.DB, "users", ["id", "username", "email", "password_hash", "role", "displayName", "status"]);\n  await c.env.DB.prepare('\''INSERT INTO users (id, username, email, password_hash, role, displayName, status) VALUES (?, ?, ?, ?, ?, ?, ?)'\'')/' functions/api/[[path]].ts
sed -i 's/.bind(crypto.randomUUID(), username, email, password_hash, role)/.bind(crypto.randomUUID(), username, email, password_hash, role, displayName, status)/' functions/api/[[path]].ts
